from flask import Flask, request, jsonify, abort
from flask_sqlalchemy import SQLAlchemy
from flask_login import current_user, login_required

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(db.String(20), nullable=False)
    account_status = db.Column(db.String(20), nullable=False)
    subscription_tier = db.Column(db.String(20), nullable=False)

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@login_required
def update_user(user_id):
    if current_user.role != 'admin':
        return jsonify({'error': 'Unauthorized access'}), 403

    user = User.query.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json()
    if not data:
        return jsonify({'error': 'No input data provided'}), 400

    username = data.get('username')
    email = data.get('email')
    role = data.get('role')
    account_status = data.get('account_status')
    subscription_tier = data.get('subscription_tier')

    if username:
        user.username = username
    if email:
        user.email = email
    if role in ['user', 'moderator', 'admin']:
        user.role = role
    if account_status in ['active', 'suspended']:
        user.account_status = account_status
    if subscription_tier in ['free', 'pro', 'enterprise']:
        user.subscription_tier = subscription_tier

    db.session.commit()
    return jsonify({'message': 'User updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=False)